import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { ChevronRight, Zap, Leaf, Clock, Award } from 'lucide-react';
import Button from '../components/Button';
import MealCard from '../components/MealCard';
import PlanCard from '../components/PlanCard';
import ReviewCard from '../components/ReviewCard';
import HeroSection from '../components/HeroSection';
import { getMeals, getPlans, getReviews } from '../api/services';

const Home = () => {
  const [meals, setMeals] = useState([]);
  const [plans, setPlans] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [mealsRes, plansRes, reviewsRes] = await Promise.all([
          getMeals(),
          getPlans(),
          getReviews(),
        ]);
        setMeals(mealsRes.data.slice(0, 6));
        setPlans(plansRes.data);
        setReviews(reviewsRes.data.slice(0, 3));
      } catch (error) {
        console.error('Error fetching data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const whyDboxFeatures = [
    {
      icon: Zap,
      title: 'High Protein',
      description: 'Packed with protein to fuel your workouts and recovery.',
    },
    {
      icon: Leaf,
      title: 'Fresh Ingredients',
      description: 'Sourced daily from local organic farms.',
    },
    {
      icon: Clock,
      title: 'Quick Delivery',
      description: 'Fresh meals delivered to your door in 30 minutes.',
    },
    {
      icon: Award,
      title: 'Certified Nutrition',
      description: 'Planned by certified nutritionists and dietitians.',
    },
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.5 },
    },
  };

  return (
    <div className="bg-neutral-bg">
      {/* Hero Section */}
      <section className="py-20 px-6 bg-white">
        <div className="max-w-7xl mx-auto">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
            {/* Left Content */}
            <motion.div
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8 }}
            >
              <motion.h1
                className="text-5xl md:text-6xl font-poppins font-bold text-dark-text mb-6 leading-tight"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.2 }}
              >
                Fuel Your <span className="gradient-primary bg-clip-text text-transparent">Gains</span>
              </motion.h1>

              <motion.p
                className="text-lg text-gray-600 mb-8 leading-relaxed"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.4 }}
              >
                Premium diet meals delivered fresh to your door. Designed for fitness enthusiasts who demand quality nutrition without compromise.
              </motion.p>

              <motion.div
                className="flex gap-4 flex-wrap"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.6 }}
              >
                <Link to="/menu">
                  <Button variant="primary" size="lg">
                    Order Now <ChevronRight size={20} />
                  </Button>
                </Link>
                <Link to="/plans">
                  <Button variant="outline" size="lg">
                    View Plans
                  </Button>
                </Link>
              </motion.div>
            </motion.div>

            {/* Right Image */}
            <motion.div
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8 }}
              className="relative"
            >
              <div className="bg-gradient-to-br from-primary to-primary-dark rounded-2xl h-96 flex items-center justify-center text-white text-center p-8">
                <div>
                  <p className="text-6xl mb-4">🍱</p>
                  <p className="text-xl font-poppins font-bold">Premium Meal Prep</p>
                </div>
              </div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Why DBOX Section */}
      <section className="py-20 px-6">
        <div className="max-w-7xl mx-auto">
          <motion.div
            className="text-center mb-16"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
          >
            <h2 className="text-4xl font-poppins font-bold text-dark-text mb-4">
              Why Choose DBOX?
            </h2>
            <p className="text-lg text-gray-600">
              Everything you need to reach your fitness goals
            </p>
          </motion.div>

          <motion.div
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6"
            variants={containerVariants}
            initial="hidden"
            whileInView="visible"
          >
            {whyDboxFeatures.map((feature, index) => (
              <motion.div
                key={index}
                variants={itemVariants}
                className="bg-white rounded-2xl p-8 shadow-premium hover:shadow-hover transition-all duration-300 text-center"
                whileHover={{ y: -10 }}
              >
                <motion.div
                  className="inline-block p-4 bg-neutral-bg rounded-full mb-4"
                  whileHover={{ scale: 1.1, rotate: 10 }}
                >
                  <feature.icon className="text-primary" size={32} />
                </motion.div>
                <h3 className="font-poppins font-bold text-lg text-dark-text mb-2">
                  {feature.title}
                </h3>
                <p className="text-gray-600">{feature.description}</p>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </section>

      {/* Popular Meals Section */}
      <section className="py-20 px-6 bg-white">
        <div className="max-w-7xl mx-auto">
          <motion.div
            className="flex justify-between items-center mb-12"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
          >
            <div>
              <h2 className="text-4xl font-poppins font-bold text-dark-text mb-2">
                Popular Meals
              </h2>
              <p className="text-gray-600">
                Customer favorites packed with nutrition
              </p>
            </div>
            <Link to="/menu">
              <Button variant="outline">
                View All <ChevronRight size={20} />
              </Button>
            </Link>
          </motion.div>

          {loading ? (
            <div className="text-center py-12">
              <p className="text-gray-600">Loading meals...</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {meals.map((meal) => (
                <MealCard key={meal.id} meal={meal} />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Subscription Plans Section */}
      <section className="py-20 px-6">
        <div className="max-w-7xl mx-auto">
          <motion.div
            className="text-center mb-16"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
          >
            <h2 className="text-4xl font-poppins font-bold text-dark-text mb-4">
              Subscription Plans
            </h2>
            <p className="text-lg text-gray-600">
              Choose the perfect plan for your lifestyle
            </p>
          </motion.div>

          {loading ? (
            <div className="text-center py-12">
              <p className="text-gray-600">Loading plans...</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {plans.map((plan, index) => (
                <PlanCard
                  key={plan.id}
                  plan={plan}
                  isPopular={index === 1}
                />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Reviews Section */}
      <section className="py-20 px-6 bg-white">
        <div className="max-w-7xl mx-auto">
          <motion.div
            className="text-center mb-16"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
          >
            <h2 className="text-4xl font-poppins font-bold text-dark-text mb-4">
              Customer Reviews
            </h2>
            <p className="text-lg text-gray-600">
              What our customers are saying
            </p>
          </motion.div>

          {loading ? (
            <div className="text-center py-12">
              <p className="text-gray-600">Loading reviews...</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {reviews.map((review) => (
                <ReviewCard key={review.id} review={review} />
              ))}
            </div>
          )}

          <motion.div
            className="text-center mt-12"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
          >
            <Link to="/reviews">
              <Button variant="primary" size="lg">
                Read All Reviews <ChevronRight size={20} />
              </Button>
            </Link>
          </motion.div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="py-20 px-6 gradient-primary">
        <div className="max-w-4xl mx-auto text-center text-white">
          <motion.h2
            className="text-4xl font-poppins font-bold mb-6"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
          >
            Ready to Transform Your Fitness Journey?
          </motion.h2>
          <motion.p
            className="text-lg mb-8 text-gray-100"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
          >
            Join thousands of fitness enthusiasts who are already fueling their gains with DBOX.
          </motion.p>
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            <Link to="/menu">
              <Button variant="secondary" size="lg">
                Start Your Journey
              </Button>
            </Link>
          </motion.div>
        </div>
      </section>
    </div>
  );
};

export default Home;
